('VSH_2021_parent_inventory_0', 'VSH', 2021, 'parent', 'Thiết bị, vật tư, phụ tùng thay thế', 'raw_material', 101916517104.0, NULL, 'Công cụ, dụng cụ, vật tư và phụ tùng dùng để thay thế, phòng ngừa hư hỏng của tài sản, thời gian dự trữ trên 12 tháng'),
('VSH_2021_parent_inventory_1', 'VSH', 2021, 'parent', 'Dự án Thủy điện Vĩnh Sơn 2 và 3', 'real_estate_project', 98308623045.0, NULL, 'Dự án thủy điện gồm 2 hồ chứa (Hồ Suối Say và Hồ Đak Kron Bun), công suất lắp máy 30MW mỗi dự án. Theo quyết định số 1855/QĐ-HĐQT ngày 31/12/2021, HĐQT thông qua việc tiếp tục triển khai thực hiện'),
('VSH_2021_parent_inventory_2', 'VSH', 2021, 'parent', 'Dự án Thủy điện Thượng Kon Tum', 'construction_in_progress', 74131385802.0, NULL, 'Chi phí xây dựng cơ bản dở dang đang trong quá trình quyết toán. Tổ máy 1 và 2 đã chính thức vận hành thương mại lần lượt ngày 01/04/2021 và 09/04/2021. Đã chuyển 9.104.938.031.793 VND sang tài sản cố định hữu hình trong năm'),
('VSH_2021_parent_inventory_3', 'VSH', 2021, 'parent', 'Chi phí xây dựng cơ bản dở dang khác', 'construction_in_progress', 3337350838.0, NULL, NULL),
('VSH_2020_parent_inventory_0', 'VSH', 2020, 'parent', 'Vật liệu xây dựng cơ bản', 'raw_material', 100662618952.0, NULL, 'Chủ yếu bao gồm thiết bị phục vụ hoạt động đầu tư xây dựng cơ bản của Dự án Thủy điện Thượng Kon Tum với tổng giá trị là 56.556.617.939 VND'),
('VSH_2020_parent_inventory_1', 'VSH', 2020, 'parent', 'Dự án Thủy điện Thượng Kon Tum', 'construction_in_progress', 8702032508082.0, NULL, 'Công trình trên cùng hệ thống bậc thang thủy điện sông Sê San. Công suất lắp máy khoảng 240 MW. Đang trong quá trình nghiệm thu và bàn giao để đi vào vận hành chính thức.'),
