('VSF_2024_consolidated_inventory_2', 'VSF', 2024, 'consolidated', 'Hàng hóa bất động sản tại KCN Nhơn Hòa, Bình Định', 'real_estate_project', 46272823236.0, 0.0, 'Đất và tài sản gắn liền trên đất tại Khu Công nghiệp Nhơn Hòa, thị xã An Nhơn, tỉnh Bình Định. Toàn bộ đang bị phong tỏa cho mục đích điều tra xét xử vụ án liên quan đến khoản phải thu khó đòi với Công ty CP Tập đoàn Thịnh Phát Kon Tum.'),
('VSF_2024_consolidated_inventory_3', 'VSF', 2024, 'consolidated', 'Dự án Kho trung tâm Khánh Hưng', 'construction_in_progress', 5457758801.0, 0.0, 'Dự án đang tạm dừng theo Tờ trình số 1394/TT.LTLA.ĐTKT ngày 30/10/2018, đã được UBND tỉnh Long An phê duyệt ngày 07/5/2019. Chi nhánh Công ty Lương thực Long An đã xin gia hạn nhưng chưa nhận được phản hồi.'),
('VSF_2024_consolidated_inventory_4', 'VSF', 2024, 'consolidated', 'Nhà máy chế biến thủy sản', 'construction_in_progress', 2198239597.0, 0.0, NULL),
('VSF_2024_consolidated_inventory_5', 'VSF', 2024, 'consolidated', 'Hàng tồn kho thiếu chờ xử lý - Công ty Lương thực Trà Vinh', 'finished_goods', 649082043143.0, -649082043143.0, '83.313.922 kg gạo thiếu theo kết quả kiểm kê đột xuất ngày 22/11/2017. Đã trích lập dự phòng tổn thất toàn bộ. Tòa án đã tuyên án bồi thường 132,9 tỷ đồng. Chi cục thi hành án đã ban hành quyết định thi hành án ngày 06/01/2023.'),
('VSF_2023_parent_inventory_0', 'VSF', 2023, 'parent', 'Nguyên liệu, vật liệu', 'raw_material', 227661687205.0, 7784517275.0, NULL),
