('VSF_2023_parent_inventory_2', 'VSF', 2023, 'parent', 'Hàng hóa bất động sản', 'real_estate_project', 46272823236.0, 0.0, 'Đất và tài sản gắn liền trên đất tại Khu Công nghiệp Nhon Hòa, thị xã An Nhơn, tỉnh Bình Định, đang bị phong tỏa do điều tra xét xử vụ án.'),
('VSF_2023_parent_inventory_3', 'VSF', 2023, 'parent', 'Chi phí xây dựng cơ bản dở dang', 'construction_in_progress', 11160499202.0, 0.0, 'Bao gồm Dự án Kho trung tâm Khánh Hưng, mua sắm TSCĐ, sửa chữa lớn TSCĐ, nhà máy chế biến thủy sản.'),
('VSF_2022_consolidated_inventory_0', 'VSF', 2022, 'consolidated', 'Hàng tồn kho gạo, lúa mì, ngũ cốc, bột mì, nguyên liệu và thành phẩm', 'finished_goods', 1172060142929.0, 26824057895.0, 'Hàng tồn kho bao gồm gạo, lúa mì, hạt ngũ cốc, bột mì, nguyên liệu, thành phẩm. Trong đó có hàng hóa bất động sản (đất và tài sản gắn liền tại KCN Nhơn Hòa, Bình Định) bị phong tỏa phục vụ điều tra; Khu đất dự án Khu dân cư Hoàng Hải, Hóc Môn. Có 132.281 triệu VND được thế chấp đảm bảo cho khoản vay.'),
('VSF_2022_consolidated_inventory_1', 'VSF', 2022, 'consolidated', 'Hàng tồn kho thiếu chờ xử lý - Công ty Lương thực Trà Vinh', 'raw_material', 661975531134.0, 661975531134.0, 'Hàng tồn kho thiếu 83.314 Kg theo Báo cáo kiểm kê đột xuất ngày 22/11/2017. Đã dự phòng tổn thất toàn bộ. Tòa án Nhân dân TP.HCM ban hành Quyết định thi hành án số 1456/QĐ-CTHADS yêu cầu bồi thường 132,9 tỷ đồng nhưng người thi hành án chưa thực hiện.'),
('VSF_2022_consolidated_inventory_2', 'VSF', 2022, 'consolidated', 'Dự án Kho trung tâm Khánh Hưng (Long An)', 'construction_in_progress', 5457758801.0, NULL, 'Dự án tạm dừng theo Tờ trình số 1394/TT.LTLA.DTKT. Đã được UBND tỉnh Long An phê duyệt ngày 7/5/2019. Công ty Lương thực Long An xin gia hạn nhưng chưa nhận được phản hồi.'),
('VSF_2022_consolidated_inventory_3', 'VSF', 2022, 'consolidated', 'Dự án đầu tư kho Năng Gù', 'construction_in_progress', 2197807720.0, NULL, NULL),
('VSF_2022_consolidated_inventory_4', 'VSF', 2022, 'consolidated', 'Chi phí xây dựng cơ bản dở dang khác', 'construction_in_progress', 22471519434.0, NULL, 'Bao gồm: Công trình mở rộng sân phơi, nhà ở công nhân tại Xí nghiệp cá cơm; Quyền sử dụng đất tại 265 Điện Biên Phủ (đã hết hiệu lực chuyển nhượng); Chi phí lập dự án nhà cao tầng tại 1458 Hoài Thanh (vướng thủ tục); Chi phí chuyển mục đích sử dụng đất tại 1484 Võ Văn Kiệt (chưa thẩm định giá); Sửa chữa lớn TSCĐ và mua sắm khác.');
