('VRG_2025_consolidated_inventory_0', 'VRG', 2025, 'consolidated', 'Nguyên liệu, vật liệu', 'raw_material', 139620390.0, NULL, 'Nguyên liệu, vật liệu tồn kho theo giá bình quân gia quyền'),
('VRG_2025_consolidated_inventory_1', 'VRG', 2025, 'consolidated', 'Công cụ, dụng cụ', 'raw_material', 1200000.0, NULL, NULL),
('VRG_2025_consolidated_inventory_2', 'VRG', 2025, 'consolidated', 'Dự án đầu tư xây dựng và kinh doanh kết cấu hạ tầng Khu công nghiệp Cộng Hòa', 'construction_in_progress', 163473361797.0, NULL, 'Dự án tại phường Cộng Hòa, Thành phố Chí Linh, tỉnh Hải Dương. Giấy chứng nhận đăng ký đầu tư số 0227553775. Tổng mức đầu tư hơn 1.250 tỷ đồng theo Nghị quyết ĐHĐCĐ thường niên 2024. Giai đoạn 1: Quý II/2008 - Quý II/2024; Giai đoạn 2: Quý III/2024 - Quý IV/2025. Chi phí phát sinh trong năm: 17.807.144.611 đồng; Kết chuyển vào TSCĐ trong năm: 184.606.277.318 đồng.'),
('VRG_2025_consolidated_inventory_3', 'VRG', 2025, 'consolidated', 'Bất động sản đầu tư - Cơ sở hạ tầng cho thuê (Lô B5, B6, B7 KCN Cộng Hòa)', 'real_estate_project', 231235619727.0, NULL, 'Bất động sản đầu tư cho thuê, nguyên giá 260.046.540.096 đồng, hao mòn lũy kế 28.810.920.369 đồng. Tăng trong năm do ghi nhận Cơ sở hạ tầng Lô đất B5, B6, B7 thuộc KCN Cộng Hòa.'),
